		}
	}

	maxVal := getMax(arr)

	for exp := 1; maxVal/exp > 0; exp *= 10 {
		countSort(arr, exp)
	}

	if offset > 0 {
		for i := range arr {
			arr[i] -= offset
		}
	}
}

